func TestOptionsConfigCustomResourceConfigFileLegacyKey(t *testing.T) {
	configFile := []byte(`custom_resource_config_file: custom-resource-config.yaml`)
	opts := NewOptions()

	if err := yaml.Unmarshal(configFile, opts); err != nil {
		t.Fatalf("failed to unmarshal config file: %v", err)
	}

	if opts.CustomResourceConfigFile != "custom-resource-config.yaml" {
		t.Fatalf("expected custom resource config file to be set, got %q", opts.CustomResourceConfigFile)
	}
}

func TestOptionsParse(t *testing.T) {
	tests := []struct {
		Desc         string
		Args         []string
		ExpectsError bool
	}{
		{
			Desc:         "resources command line argument",
			Args:         []string{"./kube-state-metrics", "--resources=configmaps,pods"},
			ExpectsError: false,
		},
		{
			Desc:         "namespaces command line argument",
			Args:         []string{"./kube-state-metrics", "--namespaces=default,kube-system"},
			ExpectsError: false,
		},
		{
			Desc:         "foo command line argument",
			Args:         []string{"./kube-state-metrics", "--foo=bar,baz"},
			ExpectsError: true,
		},
	}

	opts := NewOptions()
	opts.AddFlags(InitCommand)

	for _, test := range tests {
		t.Run(test.Desc, func(t *testing.T) {
			os.Args = test.Args

			err := opts.Parse()

			if !test.ExpectsError && err != nil {
				t.Errorf("Error for test with description: %s: %v", test.Desc, err.Error())
			}

			if test.ExpectsError && err == nil {
				t.Errorf("Expected error for test with description: %s", test.Desc)
			}
		})
	}
}

